# Security: Query Cost Analysis
@dataclass
class QueryCostTracker:
    max_cost: int = 10000
    max_depth: int = 10
    current_cost: int = 0
    current_depth: int = 0
    field_costs: dict = field(default_factory=lambda: {
        'Product': 1,
        'Seller': 1,
        'Review': 1,
        'Category': 1,
        'Image': 1,
        'products': 10,
        'reviews': 5,
        'images': 2,
        'categories': 2,
        'seller': 1,
    })
    
    def calculate_cost(self, field_name: str, multiplier: int = 1) -> int:
        base_cost = self.field_costs.get(field_name, 1)
        return base_cost * multiplier
    
    def add_cost(self, cost: int):
        self.current_cost += cost
        if self.current_cost > self.max_cost:
            raise Exception(f"Query cost {self.current_cost} exceeds maximum allowed cost {self.max_cost}")
    
    def increment_depth(self):
        self.current_depth += 1
        if self.current_depth > self.max_depth:
            raise Exception(f"Query depth {self.current_depth} exceeds maximum allowed depth {self.max_depth}")
    
    def decrement_depth(self):
        self.current_depth -= 1


# Security: Rate Limiting
class RateLimiter:
    def __init__(self, max_requests: int = 100, window_seconds: int = 60):
        self.max_requests = max_requests
        self.window_seconds = window_seconds
        self.requests = defaultdict(list)
    
    def check_rate_limit(self, identifier: str):
        current_time = time.time()
        self.requests[identifier] = [
            req_time for req_time in self.requests[identifier]
            if current_time - req_time < self.window_seconds
        ]
        
        if len(self.requests[identifier]) >= self.max_requests:
            raise Exception(f"Rate limit exceeded. Maximum {self.max_requests} requests per {self.window_seconds} seconds")
        
        self.requests[identifier].append(current_time)


# Security: Query Allowlist (Persisted Queries)
class QueryAllowlist:
    def __init__(self):
        self.allowed_hashes = set()
        self.enabled = False
    
    def enable(self):
        self.enabled = True
    
    def add_query(self, query: str):
        query_hash = hashlib.sha256(query.encode()).hexdigest()
        self.allowed_hashes.add(query_hash)
        return query_hash
    
    def validate_query(self, query: str):
        if not self.enabled:
            return True
        query_hash = hashlib.sha256(query.encode()).hexdigest()
        if query_hash not in self.allowed_hashes:
            raise Exception("Query not in allowlist. Use persisted queries.")
        return True


# Security: Input Validation
def validate_pagination(limit: Optional[int], offset: Optional[int]):
    max_limit = 100
    if limit and limit > max_limit:
        raise Exception(f"Limit cannot exceed {max_limit}")
    if offset and offset < 0:
        raise Exception("Offset cannot be negative")
    if limit and limit < 0:
        raise Exception("Limit cannot be negative")


# DataLoader for N+1 query prevention
class DataLoaderContext:
    def __init__(self, db: Session):
        self.db = db
        self.seller_loader = {}
        self.reviews_loader = {}
        self.images_loader = {}
        self.categories_loader = {}
    
    def load_sellers(self, seller_ids: List[int]) -> dict:
        if not seller_ids:
            return {}
        sellers = self.db.query(SellerModel).filter(SellerModel.id.in_(seller_ids)).all()
        return {seller.id: seller for seller in sellers}
    
    def load_reviews_for_products(self, product_ids: List[int]) -> dict:
        if not product_ids:
            return {}
        reviews = self.db.query(ReviewModel).filter(ReviewModel.product_id.in_(product_ids)).all()
        result = defaultdict(list)
        for review in reviews:
            result[review.product_id].append(review)
        return result
    
    def load_images_for_products(self, product_ids: List[int]) -> dict:
        if not product_ids:
            return {}
        images = self.db.query(ImageModel).filter(ImageModel.product_id.in_(product_ids)).all()
        result = defaultdict(list)
        for image in images:
            result[image.product_id].append(image)
        return result


